import csv
from collections import defaultdict

custs = {}
with open('customers.csv') as f:
    for r in csv.DictReader(f):
        custs[r['customer_id']] = r['email']

totals = defaultdict(float)
with open('orders.csv') as f:
    for r in csv.DictReader(f):
        cid = r['customer_id']
        if cid in custs:
            totals[custs[cid]] += float(r['amount'])

for email, total in sorted(totals.items()):
    print(f'{email},{total}')
